Show that there is a one-to-one correspondence between the Dyck  $n$-paths
with no return of even length and the Dyck $(n-1)$-paths.

Let $k$ be an integer greater than 1. Suppose $a_0 > 0$, and define
\[
a_{n+1} = a_n + \frac{1}{\sqrt[k]{a_n}}
\]
for $n > 0$. Evaluate
\[
\lim_{n \to \infty} \frac{a_n^{k+1}}{n^k}.
\]
\end{itemize}

\end{document}

Let $f: (1, \infty) \to \mathbb{R}$ be a differentiable function such that
\[
 f'(x) = \frac{x^2 - f(x)^2}{x^2 (f(x)^2 + 1)}
\qquad \mbox{for all $x>1$.}
\]
Prove that $\lim_{x \to \infty} f(x) = \infty$.

problems.solution_tex:
We start with three lemmas.
\setcounter{lemma}{0}
\begin{lemma}
If $\mathbf{x},\mathbf{y} \in G$ are nonzero orthogonal vectors, then $\mathbf{x}*\mathbf{x}$ is parallel to $\mathbf{y}$.
\end{lemma}
\begin{proof}
Put $\mathbf{z} = \mathbf{x} \times \mathbf{y} \neq 0$, so that $\mathbf{x},\mathbf{y}$, and $\mathbf{z} = \mathbf{x}*\mathbf{y}$ are nonzero and mutually orthogonal.
Then $\mathbf{w} = \mathbf{x} \times \mathbf{z} \neq 0$, so $\mathbf{w} = \mathbf{x}*\mathbf{z}$ is nonzero and orthogonal to $\mathbf{x}$ and $\mathbf{z}$.
However, if $(\mathbf{x}*\mathbf{x}) \times \mathbf{y} \neq 0$, then $\mathbf{w} = \mathbf{x}*(\mathbf{x}*\mathbf{y}) = (\mathbf{x}*\mathbf{x})*\mathbf{y} = (\mathbf{x}*\mathbf{x}) \times \mathbf{y}$ is also orthogonal to $\mathbf{y}$, a contradiction.
\end{proof}
\begin{lemma}
If $\mathbf{x} \in G$ is nonzero, and there exists $\mathbf{y} \in G$ nonzero and orthogonal to $\mathbf{x}$, then $\mathbf{x}*\mathbf{x} = 0$.
\end{lemma}
\begin{proof}
Lemma~1 implies that $\mathbf{x}*\mathbf{x}$ is parallel to both $\mathbf{y}$ and $\mathbf{x} \times \mathbf{y}$, so it must be zero.
\end{proof}
\begin{lemma}
If $\mathbf{x},\mathbf{y} \in G$ commute, then $\mathbf{x} \times \mathbf{y} = 0$.
\end{lemma}
\begin{proof}
If $\mathbf{x} \times \mathbf{y} \neq 0$, then $\mathbf{y} \times \mathbf{x}$ is nonzero
and distinct from $\mathbf{x} \times \mathbf{y}$. Consequently,
$\mathbf{x}*\mathbf{y} = \mathbf{x} \times \mathbf{y}$
and $\mathbf{y}*\mathbf{x} = \mathbf{y} \times \mathbf{x} \neq \mathbf{x} * \mathbf{y}$.
\end{proof}

We proceed now to the proof. Assume by way of contradiction that there exist $\mathbf{a},\mathbf{b} \in G$ with $\mathbf{a} \times \mathbf{b}
\neq 0$. Put $\mathbf{c} = \mathbf{a}\times \mathbf{b} = \mathbf{a}*\mathbf{b}$, so that $\mathbf{a},\mathbf{b},\mathbf{c}$ are nonzero and linearly independent. Let $\mathbf{e}$ be the identity
element of $G$. Since $\mathbf{e}$ commutes with $\mathbf{a},\mathbf{b},\mathbf{c}$, by Lemma~3 we have $\mathbf{e} \times \mathbf{a} = \mathbf{e} \times \mathbf{b} = \mathbf{e} \times \mathbf{c} = 0$.
Since $\mathbf{a},\mathbf{b},\mathbf{c}$ span $\RR^3$, $\mathbf{e} \times \mathbf{x} = 0$ for all $\mathbf{x} \in \RR^3$, so $\mathbf{e} = 0$.

Since $\mathbf{b},\mathbf{c}$, and $\mathbf{b} \times \mathbf{c} = \mathbf{b}*\mathbf{c}$ are nonzero and mutually orthogonal, Lemma~2 implies
\[
\mathbf{b}*\mathbf{b} = \mathbf{c}*\mathbf{c} = (\mathbf{b}*\mathbf{c})*(\mathbf{b}*\mathbf{c}) = 0 = \mathbf{e}.
\]
Hence $\mathbf{b}*\mathbf{c} = \mathbf{c}*\mathbf{b}$, contradicting Lemma~3 because $\mathbf{b} \times \mathbf{c} \neq 0$.
The desired result follows.

problems.problem_tex:
Let $A$ be an $n \times n$ matrix of real numbers for some $n \geq 1$.
For each positive integer $k$, let $A^{[k]}$ be the matrix obtained by raising each entry to the $k$th
power. Show that if $A^k = A^{[k]}$ for $k=1,2,\dots,n+1$, then $A^k = A^{[k]}$ for all $k \geq 1$.

\end{itemize}

\end{document}

problems.solution_tex:
For any polynomial $p(x)$, let $[p(x)]A$ denote the $n\times n$ matrix obtained by replacing each entry $A_{ij}$ of $A$ by $p(A_{ij})$; thus $A^{[k]} = [x^k]A$. Let $P(x) = x^n + a_{n-1}x^{n-1} + \cdots + a_0$ denote the characteristic polynomial of $A$. By the Cayley-Hamilton theorem,
\begin{align*}
0 &= A \cdot P(A) \\
&= A^{n+1} + a_{n-1}A^n+\cdots+a_0 A \\
&= A^{[n+1]}+a_{n-1}A^{[n]}+\cdots + a_0 A^{[1]} \\
&=[xp(x)]A.
\end{align*}
Thus each entry of $A$ is a root of the polynomial $xp(x)$.

Now suppose $m \geq n+1$. Then
\begin{align*}
0 &= [x^{m+1-n}P(x)]A  \\
&= A^{[m+1]} + a_{n-1} A^{[m]} + \cdots + a_0 A^{[m+1-n]}
\end{align*}
since each entry of $A$ is a root of $x^{m+1-n}P(x)$. On the other hand,
\begin{align*}
0 &= A^{m+1-n} \cdot P(A) \\
&= A^{m+1} + a_{n-1} A^m + \cdots + a_0 A^{m+1-n}.
\end{align*}
Therefore if $A^k = A^{[k]}$ for $m+1-n \leq k \leq m$, then $A^{m+1} = A^{[m+1]}$. The desired result follows by induction on $m$.

\textbf{Remark.}
David Feldman points out that the result is best possible in the following sense: there exist
examples of $n \times n$ matrices $A$ for which $A^k = A^{[k]}$ for $k=1,\dots,n$ but $A^{n+1} \neq A^{[n+1]}$.

\end{itemize}
\end{document}

problems.problem_tex:
Let $F : \RR^2 \to \RR$ and $g : \RR \to \RR$ be twice
continuously differentiable functions with the following properties:
\begin{itemize}
\item $F(u,u) = 0$ for every $u \in \RR$;
\item for every $x \in \RR$, $g(x) > 0$ and $x^2 g(x) \leq 1$;
\item for every $(u,v) \in \RR^2$, the vector $\nabla F(u,v)$ is either $\mathbf{0}$ or parallel to the vector $\langle g(u), -g(v) \rangle$.
\end{itemize}
Prove that there exists a constant $C$ such that for every $n\geq 2$ and any $x_1,\dots,x_{n+1} \in \RR$, we have
\[
\min_{i \neq j} |F(x_i,x_j)| \leq \frac{C}{n}.
\]

Let $p$ be an odd prime. Show that for at least $(p+1)/2$ values of $n$ in $\{0,1,2,\dots,p-1\}$,
\[
\sum_{k=0}^{p-1} k! n^k \qquad \mbox{is not divisible by $p$.}
\]

\end{itemize}

\end{document}

Let $p$ be an odd prime number such that $p \equiv 2 \pmod{3}$. Define a permutation $\pi$ of the
residue classes modulo $p$ by $\pi(x) \equiv x^3 \pmod{p}$. Show that $\pi$ is an even permutation
if and only if $p \equiv 3 \pmod{4}$.

\end{itemize}

\end{document}

Let $C = \bigcup_{N=1}^\infty C_N$, where $C_N$ denotes the set of those `cosine polynomials' of the form
\[
f(x) = 1 + \sum_{n=1}^N a_n \cos(2 \pi n x)
\]
for which:
\begin{enumerate}

problems.solution_tex:
Yes, such numbers must exist. To define them, we make the following observations.

\setcounter{lemma}{0}
\begin{lemma}
For any $i \in \{1,\dots,n\}$, if there exists any $S \in P$ containing $i$, then there exist $S,T \in P$ such that $S$ is the disjoint union of $T$ with $\{i\}$.
\end{lemma}
\begin{proof}
Let $S$ be an element of $P$ containing $i$ of minimum cardinality.
By (ii), there must be a subset $T \subset S$ containing $P$ with exactly one fewer element than $S$. These sets have the desired form.
\end{proof}

\begin{lemma}
Suppose $S_1, S_2, T_1, T_2 \in P$ have the property that for some $i \in \{1,\dots,n\}$, $S_1$ is the disjoint union of $T_1$ with $\{i\}$ and $S_2$ is the disjoint union of $T_2$ with $\{i\}$. Then 
\[
f(S_1) - f(T_1) = f(S_2) - f(T_2).
\]
\end{lemma}
\begin{proof}
By (i) we have
\begin{align*}
f(T_1 \cup T_2 \cup \{i\}) &= f(S_1) + f(T_2) - f(T_1 \cap T_2) \\
f(T_1 \cup T_2 \cup \{i\}) &= f(T_1) + f(S_2) - f(T_1 \cap T_2),
\end{align*}
from which the claim follows immediately.
\end{proof}

We now define $f_1,\dots,f_n$ as follows. If $i$ does not appear in any element of $P$, we put $f_i = 0$. Otherwise, by Lemma~1, we can find 
$S, T \in P$ such that $S$ is the disjoint union of $T$ with $\{i\}$. We then set $f_i = f(S) - f(T)$; by Lemma~2, this does not depend on the choice of $S,T$.

To check that $f(S) = \sum_{i \in S} f_i$ for $S \in P$, note first that $\emptyset \in P$ by repeated application of (ii) and that $f(\emptyset) = 0$ by hypothesis. This provides the base case for an induction on the cardinality of $S$; for any nonempty $S \in P$, we may apply (ii) to find $T \subset S$ such that $S$ is the disjoint union of $T$ and some singleton set $\{j\}$. By construction and the induction hypothesis, we have $f(S) = f(T) + f_j = j + \sum_{i \in T} f_i = \sum_{i \in S} f_i$ as desired.

\newcommand{\Var}{\mathrm{Var}}

Write $f_0(x) = f(x)-\mu(f)$ and $g_0(x) = g(x)-\mu(g)$, so that $\int_0^1 f_0(x)^2\,dx = \Var(f)$, $\int_0^1 g_0(x)^2\,dx = \Var(g)$, and $\int_0^1 f_0(x)\,dx = \int_0^1 g_0(x)\,dx = 0$. Now since $|g(x)| \leq M(g)$ for all $x$, $0\leq \int_0^1 f_0(x)^2(M(g)^2-g(x)^2)\,dx = \Var(f) M(g)^2-\int_0^1 f_0(x)^2g(x)^2\,dx$, and similarly $0 \leq \Var(g)M(f)^2-\int_0^1 f(x)^2g_0(x)^2\,dx$. Summing gives
\begin{equation}
\Var(f)M(g)^2+\Var(g)M(f)^2
\label{eq:1}
\geq \int_0^1 (f_0(x)^2g(x)^2+f(x)^2g_0(x)^2)\,dx.
\end{equation}
Now
\begin{align*}
&\int_0^1 (f_0(x)^2g(x)^2+f(x)^2g_0(x)^2)\,dx-\Var(fg) \\&= \int_0^1 (f_0(x)^2g(x)^2+f(x)^2g_0(x)^2-(f(x)g(x)-\int_0^1 f(y)g(y)\,dy)^2)\,dx;
\end{align*}
substituting $f_0(x)+\mu(f)$ for $f(x)$ everywhere and $g_0(x)+\mu(g)$ for $g(x)$ everywhere, and using the fact that $\int_0^1 f_0(x)\,dx = \int_0^1 g_0(x)\,dx = 0$, we can expand and simplify the right hand side of this equation to obtain
\begin{align*}
&\int_0^1 (f_0(x)^2g(x)^2+f(x)^2g_0(x)^2)\,dx-\Var(fg) \\
&= \int_0^1 f_0(x)^2g_0(x)^2\,dx \\
&-2\mu(f)\mu(g)\int_0^1 f_0(x)g_0(x)\,dx +(\int_0^1 f_0(x)g_0(x)\,dx)^2 \\
&\geq -2\mu(f)\mu(g)\int_0^1 f_0(x)g_0(x)\,dx.
\end{align*}
Because of \eqref{eq:1}, it thus suffices to show that
\begin{equation}
2\mu(f)\mu(g)\int_0^1 f_0(x)g_0(x)\,dx
\label{eq:3} \leq \Var(f)M(g)^2+\Var(g)M(f)^2.
\end{equation}
Now since $(\mu(g) f_0(x)-\mu(f) g_0(x))^2 \geq 0$ for all $x$, we have
\begin{align*}
2\mu(f)\mu(g) \int_0^1 f_0(x)g_0(x)\,dx
& \leq \int_0^1 (\mu(g)^2 f_0(x)^2 + \mu(f)^2 g_0(x)^2) dx \\
& = \Var(f) \mu(g)^2 + \Var(g) \mu(f)^2 \\
& \leq \Var(f) M(g)^2 + \Var(g) M(f)^2,
\end{align*}
establishing \eqref{eq:3} and completing the proof.

problems.problem_tex:
For each positive integer $k$, let $A(k)$ be the number of odd divisors of $k$ in the interval $[1, \sqrt{2k})$. Evaluate
\[
\sum_{k=1}^\infty (-1)^{k-1} \frac{A(k)}{k}.
\]

\end{itemize}

